/**
 * Maturity assessment results Screen
 *
 * Displays assessment results including:
 * - Operational and Strategic maturity scoring
 * - Maturity positioning matrix (2D heatmap)
 * - Strategic analysis (symptoms, risks, opportunities)
 * - Recommended actions
 * - Implementation blockers
 * - Detailed responses (collapsible)
 *
 * Completely client-side - NO backend/database required
 * Uses localStorage for assessment data and bundled reference data
 */

import { useEffect, useState } from 'react';
import { useLocation } from 'wouter';
import {
  AlertTriangle,
  Lightbulb,
  Shield,
  TrendingUp,
  Users,
  BarChart3,
  CheckCircle,
  RefreshCw,
  User,
  Building2,
  Settings,
  Target,
  Bot
} from 'lucide-react';
import {
  generateMaturityResults,
  calculateScoresFromAnswers,
  getBandDescription
} from '@/utils/maturityBanding';
import { useParentCommunication } from '@/hooks/useParentCommunication';
import {
  MaturitySegmentDisplay,
  SectionHeader
} from '@/components/maturity';
import {
  getSegmentByBands,
  getActionsForSegment,
  type MaturitySegment,
  type RecommendedAction
} from '@/data/referenceData';
import { maturityQuestions } from '@/constants/maturityQuestions';
import type { MaturityResults as MaturityResultsType } from '@shared/types';

interface MaturityResultsProps {
  sessionId: string | null;
}

interface StoredAssessment {
  sessionId: string;
  answers: number[];
  blockers: string[];
  otherBlockers: string;
  completedAt: string;
}

// Icon mapping for action types
const getActionIcon = (actionType: string) => {
  switch (actionType?.toLowerCase()) {
    case 'foundation': return Shield;
    case 'quick win': return TrendingUp;
    case 'governance': return Users;
    case 'analytics': return BarChart3;
    case 'scale': return TrendingUp;
    default: return CheckCircle;
  }
};

// Tier icon based on maturity level
const getTierIcon = (tier: string) => {
  switch (tier?.toLowerCase()) {
    case 'autonomous': return TrendingUp;
    case 'controlled': return Shield;
    case 'managed': return Users;
    case 'siloed': return BarChart3;
    default: return AlertTriangle;
  }
};

export default function MaturityResults({ sessionId }: MaturityResultsProps) {
  useParentCommunication();
  const [, setLocation] = useLocation();
  const [maturityResults, setMaturityResults] = useState<MaturityResultsType | null>(null);
  const [assessmentData, setAssessmentData] = useState<StoredAssessment | null>(null);
  const [segmentData, setSegmentData] = useState<MaturitySegment | null>(null);
  const [actionsData, setActionsData] = useState<RecommendedAction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showDetailedResponses, setShowDetailedResponses] = useState(false);

  // Get session ID from URL if not provided
  const urlParams = new URLSearchParams(window.location.search);
  const effectiveSessionId = sessionId || urlParams.get('session') || urlParams.get('s');

  // Load assessment data from localStorage
  useEffect(() => {
    if (!effectiveSessionId) {
      setIsLoading(false);
      return;
    }

    const storedData = localStorage.getItem(`assessment_${effectiveSessionId}`);
    if (storedData) {
      try {
        const parsed = JSON.parse(storedData) as StoredAssessment;
        setAssessmentData(parsed);

        // Calculate maturity results
        const { operationalScore, strategicScore } = calculateScoresFromAnswers(parsed.answers);
        const results = generateMaturityResults(operationalScore, strategicScore);
        setMaturityResults(results);

        // Get segment data from bundled reference data
        const segment = getSegmentByBands(results.operationalBand, results.strategicBand);
        if (segment) {
          setSegmentData(segment);

          // Get actions for this segment
          const actions = getActionsForSegment(segment.id);
          setActionsData(actions);
        }
      } catch (e) {
        console.error('Failed to parse assessment data:', e);
      }
    }

    setIsLoading(false);
  }, [effectiveSessionId]);

  // Loading state
  if (isLoading) {
    return (
      <div className="min-h-screen bg-[#082029] flex items-center justify-center p-4">
        <div className="text-center">
          <RefreshCw className="w-8 h-8 text-[#34E5E2] animate-spin mx-auto mb-4" />
          <p className="text-[#F2F2F2]">Loading results...</p>
        </div>
      </div>
    );
  }

  // No session or data found
  if (!effectiveSessionId || !assessmentData) {
    return (
      <div className="min-h-screen bg-[#082029] flex items-center justify-center p-4">
        <div className="text-center max-w-md mx-auto p-6">
          <AlertTriangle className="w-12 h-12 text-[#E24650] mx-auto mb-4" />
          <h2 className="text-xl font-bold text-[#34E5E2] mb-2">Assessment not found</h2>
          <p className="text-[#F2F2F2] mb-6">
            We couldn't find your assessment results. Please complete an assessment first.
          </p>
          <button
            onClick={() => setLocation('/assessment')}
            className="btn btn-primary"
          >
            Start new assessment
          </button>
        </div>
      </div>
    );
  }

  if (!maturityResults) {
    return (
      <div className="min-h-screen bg-[#082029] flex items-center justify-center p-4">
        <div className="text-center">
          <RefreshCw className="w-8 h-8 text-[#34E5E2] animate-spin mx-auto mb-4" />
          <p className="text-[#F2F2F2]">Calculating results...</p>
        </div>
      </div>
    );
  }

  const { operationalBand, operationalScore, strategicScore } = maturityResults;
  const currentTier = operationalBand; // Use operational band as the primary tier
  const TierIcon = getTierIcon(currentTier);

  return (
    <div className="min-h-screen bg-[#082029] p-4 sm:p-6 lg:p-8">
      <div className="max-w-[1400px] mx-auto space-y-8">
        {/* Page Header */}
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mb-8">
          <div className="text-center sm:text-left">
            <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-[#34E5E2] mb-2">
              Maturity assessment results
            </h1>
            <p className="text-[#F2F2F2]">
              R2R maturity assessment for your organization
            </p>
          </div>
        </div>

        {/* Summary Header Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
            <div className="flex items-center gap-3 mb-3">
              <div className="p-2 bg-[#006170]/10 rounded-lg">
                <TierIcon className="w-5 h-5 text-[#34E5E2]" />
              </div>
              <span className="text-sm text-[#F2F2F2] font-medium">Strategic position</span>
            </div>
            <div className="text-2xl font-bold text-[#34E5E2] mb-1">{currentTier}</div>
            <p className="text-sm text-[#34E5E2]">{getBandDescription(currentTier)}</p>
          </div>

          <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
            <div className="flex items-center gap-3 mb-3">
              <span className="text-sm text-[#F2F2F2] font-medium">Operational score</span>
            </div>
            <div className="text-2xl font-bold text-[#34E5E2] mb-1">{operationalScore} / 30</div>
            <div className="w-full bg-[#006170]/30 rounded-full h-2 mt-2">
              <div
                className="bg-[#006170] rounded-full h-2 transition-all"
                style={{ width: `${(operationalScore / 30) * 100}%` }}
              />
            </div>
          </div>

          <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
            <div className="flex items-center gap-3 mb-3">
              <span className="text-sm text-[#F2F2F2] font-medium">Strategic score</span>
            </div>
            <div className="text-2xl font-bold text-[#34E5E2] mb-1">{strategicScore} / 25</div>
            <div className="w-full bg-[#006170]/30 rounded-full h-2 mt-2">
              <div
                className="bg-[#006170] rounded-full h-2 transition-all"
                style={{ width: `${(strategicScore / 25) * 100}%` }}
              />
            </div>
          </div>
        </div>

        {/* maturity positioning Matrix */}
        <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
          <SectionHeader
            title="R2R maturity positioning"
            subtitle="Your organization's position on the operational vs. strategic maturity matrix"
          />
          <MaturitySegmentDisplay
            operationalScore={operationalScore}
            strategicScore={strategicScore}
          />
        </div>

        {/* Strategic Analysis */}
        {segmentData && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
              <div className="flex items-center gap-2 mb-4">
                <AlertTriangle className="w-5 h-5 text-[#E24650]" />
                <h3 className="text-lg font-semibold text-[#34E5E2]">Key symptoms</h3>
              </div>
              <p className="text-[#F2F2F2] text-sm leading-relaxed">{segmentData.symptoms}</p>
            </div>

            <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
              <div className="flex items-center gap-2 mb-4">
                <Shield className="w-5 h-5 text-[#E24650]" />
                <h3 className="text-lg font-semibold text-[#34E5E2]">Primary risks</h3>
              </div>
              <p className="text-[#F2F2F2] text-sm leading-relaxed">{segmentData.risks}</p>
            </div>

            <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
              <div className="flex items-center gap-2 mb-4">
                <Lightbulb className="w-5 h-5 text-[#34E5E2]" />
                <h3 className="text-lg font-semibold text-[#34E5E2]">Key opportunities</h3>
              </div>
              <p className="text-[#F2F2F2] text-sm leading-relaxed">{segmentData.opportunities}</p>
            </div>
          </div>
        )}

        {/* Headline Message */}
        {segmentData && (
          <div className="bg-gradient-to-r from-[#006170] to-[#082029] rounded-xl p-6 border border-[#34E5E2]">
            <h3 className="text-xl font-bold text-[#34E5E2] mb-2">{segmentData.headline_message}</h3>
            <p className="text-[#F2F2F2]">{segmentData.summary_diagnosis}</p>
          </div>
        )}

        {/* Recommended actions */}
        {actionsData.length > 0 && (
          <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
            <SectionHeader
              title="Recommended actions"
              subtitle="Prioritized steps to advance your maturity"
            />
            <div className="space-y-4 mt-6">
              {actionsData.slice(0, 5).map((action, index) => {
                const ActionIcon = getActionIcon(action.action_type);
                return (
                  <div
                    key={action.id}
                    className="bg-[#082029] rounded-lg p-4 border border-[#006170]/40"
                  >
                    <div className="flex items-start gap-4">
                      <div className="flex-shrink-0 w-8 h-8 bg-[#006170]/10 rounded-full flex items-center justify-center">
                        <ActionIcon className="w-4 h-4 text-[#34E5E2]" />
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <h4 className="font-semibold text-[#34E5E2]">{action.action_title}</h4>
                          <span className="text-xs px-2 py-0.5 bg-[#006170]/30 rounded-full text-[#F2F2F2]">
                            {action.action_type}
                          </span>
                          <span className="text-xs px-2 py-0.5 bg-[#006170]/10 rounded-full text-[#34E5E2]">
                            {action.time_horizon}
                          </span>
                        </div>
                        <p className="text-sm text-[#F2F2F2] mb-2">{action.action_rationale}</p>
                        <p className="text-sm text-[#34E5E2]">
                          <strong>Expected outcome:</strong> {action.expected_outcome}
                        </p>
                      </div>
                      <div className="text-right">
                        <span className="text-2xl font-bold text-[#34E5E2]">#{index + 1}</span>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Implementation blockers */}
        {(assessmentData.blockers.length > 0 || assessmentData.otherBlockers) && (
          <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
            <SectionHeader
              title="Implementation blockers"
              subtitle="Challenges identified that may impact implementation"
            />
            <div className="mt-4 space-y-2">
              {assessmentData.blockers.map((blocker, index) => (
                <div key={index} className="flex items-center gap-2 text-[#F2F2F2]">
                  <div className="w-2 h-2 bg-[#E24650] rounded-full" />
                  <span>{blocker}</span>
                </div>
              ))}
              {assessmentData.otherBlockers && (
                <div className="mt-4 p-3 bg-[#082029] rounded-lg">
                  <p className="text-sm text-[#F2F2F2] mb-1">Additional notes:</p>
                  <p className="text-[#F2F2F2]">{assessmentData.otherBlockers}</p>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Detailed maturity responses */}
        <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
          <SectionHeader
            title="Detailed maturity responses"
            subtitle="View individual question responses and selected assessment choices"
          />

          <button
            onClick={() => setShowDetailedResponses(!showDetailedResponses)}
            className="btn btn-outline mt-4 mx-auto block"
          >
            {showDetailedResponses ? 'Hide detailed maturity responses' : 'Show detailed maturity responses'}
          </button>

          {showDetailedResponses && (
            <div className="mt-6 space-y-8">
              {/* Operational excellence Section */}
              <div>
                <h4 className="text-xl font-bold text-[#34E5E2] mb-4">Operational excellence</h4>
                <div className="space-y-4">
                  {maturityQuestions.slice(0, 6).map((question, index) => {
                    const answer = assessmentData.answers[index] || 0;
                    const selectedOption = question.options[answer - 1] || '';
                    return (
                      <div key={index} className="bg-[#082029] rounded-lg p-4 border-l-4 border-[#006170]">
                        <div className="flex items-start justify-between gap-4">
                          <div className="flex-1">
                            <h5 className="font-semibold text-[#34E5E2] mb-2">{question.title}</h5>
                            <p className="text-sm text-[#F2F2F2] leading-relaxed">
                              {selectedOption}
                            </p>
                          </div>
                          <div className="text-right flex-shrink-0">
                            <div className="text-lg font-bold text-[#34E5E2]">{answer} / 5</div>
                            <div className="w-20 h-2 bg-[#006170]/30 rounded-full mt-1">
                              <div
                                className="h-2 bg-[#006170] rounded-full transition-all"
                                style={{ width: `${(answer / 5) * 100}%` }}
                              />
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Strategic maturity Section */}
              <div>
                <h4 className="text-xl font-bold text-[#34E5E2] mb-4">Strategic maturity</h4>
                <div className="space-y-4">
                  {maturityQuestions.slice(6, 11).map((question, index) => {
                    const actualIndex = index + 6;
                    const answer = assessmentData.answers[actualIndex] || 0;
                    const selectedOption = question.options[answer - 1] || '';
                    return (
                      <div key={actualIndex} className="bg-[#082029] rounded-lg p-4 border-l-4 border-[#006170]">
                        <div className="flex items-start justify-between gap-4">
                          <div className="flex-1">
                            <h5 className="font-semibold text-[#34E5E2] mb-2">{question.title}</h5>
                            <p className="text-sm text-[#F2F2F2] leading-relaxed">
                              {selectedOption}
                            </p>
                          </div>
                          <div className="text-right flex-shrink-0">
                            <div className="text-lg font-bold text-[#34E5E2]">{answer} / 5</div>
                            <div className="w-20 h-2 bg-[#006170]/30 rounded-full mt-1">
                              <div
                                className="h-2 bg-[#006170] rounded-full transition-all"
                                style={{ width: `${(answer / 5) * 100}%` }}
                              />
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Maturity level reference */}
        <div className="bg-[#082029] rounded-xl p-4 md:p-6 border border-[#006170]/40 shadow-lg">
          <SectionHeader
            title="Maturity level reference"
            subtitle="Understanding the five stages of R2R maturity"
          />
          <div className="grid grid-cols-2 sm:grid-cols-5 gap-4 mt-6">
            {[
              { level: 'Manual', icon: User, color: 'text-[#F2F2F2]', bg: 'bg-[#006170]/30', description: 'Basic processes with limited automation' },
              { level: 'Siloed', icon: Building2, color: 'text-[#34E5E2]', bg: 'bg-[#082029]', description: 'Departmental tools with minimal integration' },
              { level: 'Managed', icon: Settings, color: 'text-[#34E5E2]', bg: 'bg-[#34E5E2]/20', description: 'Coordinated processes with selective automation' },
              { level: 'Controlled', icon: Target, color: 'text-[#34E5E2]', bg: 'bg-[#34E5E2]/30', description: 'Orchestrated workflow with real-time visibility' },
              { level: 'Autonomous', icon: Bot, color: 'text-[#34E5E2]', bg: 'bg-[#006170]/20', description: 'Fully automated with predictive capabilities' }
            ].map(({ level, icon: Icon, color, bg, description }, index) => {
              const isCurrentLevel = level === operationalBand;
              return (
                <div
                  key={level}
                  className={`text-center p-4 rounded-lg transition-all ${
                    isCurrentLevel
                      ? 'bg-[#006170]/10 border-2 border-[#006170]'
                      : 'bg-[#082029] border border-[#006170]/40'
                  }`}
                >
                  <div className={`${bg} rounded-full w-10 h-10 flex items-center justify-center mx-auto mb-2`}>
                    <Icon className={`w-5 h-5 ${color}`} />
                  </div>
                  <div className="text-xs text-[#34E5E2] mb-1">Level {index + 1}</div>
                  <h4 className={`font-medium text-sm mb-1 ${isCurrentLevel ? 'text-[#34E5E2]' : color}`}>
                    {level}
                  </h4>
                  <p className="text-[#34E5E2] text-xs">{description}</p>
                </div>
              );
            })}
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <button
            onClick={() => {
              // Clear the current assessment from localStorage
              if (effectiveSessionId) {
                localStorage.removeItem(`assessment_${effectiveSessionId}`);
              }
              setLocation('/assessment');
            }}
            className="btn btn-outline flex items-center gap-2"
          >
            <RefreshCw className="w-4 h-4" />
            Take new assessment
          </button>
        </div>
      </div>
    </div>
  );
}
